<h1>Bills</h1><p><a class="button" href="<?=route('bill_new')?>">New bill</a></p>
<table><tr><th>Date</th><th>#</th><th>Vendor</th><th>Total</th><th>Status</th><th>Record payment</th><th>Actions</th></tr><?php foreach($bills as $b):?><tr><td><?=h($b['bill_date'])?></td><td><?=h($b['bill_number'])?></td><td><?=h($b['vendor_name'])?></td><td><?=$this->money($b['total'])?></td><td><?=h($b['status'])?></td><td><?php if($b['status']!=='paid'):?><form method="post" action="<?=route('bill_pay')?>" class="inline"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$b['id']?>"><input type="date" name="payment_date" value="<?=date('Y-m-d')?>"><input name="amount" value="<?=h($b['total'])?>"><button>Pay</button></form><?php endif;?></td><td><a href="<?=route('bill_edit')?>&id=<?=$b['id']?>">Edit</a> <form method="post" action="<?=route('bill_delete')?>" class="inline" onsubmit="return confirm('Delete this bill and related ledger entries/payments?');"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$b['id']?>"><button>Delete</button></form></td></tr><?php endforeach;?></table>
